    const normalizeOfficePageKey = (key) => {
        if (key === 'records-archive') return 'records-archive-home';
        return key;
    };

    const getOfficeAllowedPages = () => {
        const tenantType = currentUser?.tenantType || currentUser?.tenant_type;
        if (!tenantType || tenantType === 'HQ') return null;
        const pages = currentUser?.allowedPages || currentUser?.allowed_pages || [];
        if (!Array.isArray(pages)) return [];
        const normalized = pages.map(normalizeOfficePageKey).filter(Boolean);
        return [...new Set(normalized)];
    };

    const isRestrictedToHomeOnly = () => {
        const tenantType = currentUser?.tenantType || currentUser?.tenant_type;
        if (!tenantType || tenantType === 'HQ') return false;
        const allowedPages = getOfficeAllowedPages();
        return Array.isArray(allowedPages) && allowedPages.length === 0;
    };

    const getOfficeFallbackRoute = () => {
        const allowedPages = getOfficeAllowedPages();
        if (!allowedPages) return null;
        if (allowedPages.length === 0) return 'dashboard';
        const allowedRoutes = allowedPages.filter(route => routeToPath[route]);
        return allowedRoutes[0] || 'dashboard';
    };

    const isOfficeRouteAllowed = (route) => {
        if (route === 'download-app') {
            return true;
        }
        const tenantType = currentUser?.tenantType || currentUser?.tenant_type;
        if (tenantType === 'HQ') {
            return true;
        }
        if (currentUser?.entityId === 'HQ001' || currentUser?.entity_id === 'HQ001') {
            return true;
        }
        if ((route === 'strategic-management' || route === 'quality-audit') && currentUser?.role === ROLES.ADMIN) {
            return true;
        }
        const allowedPages = getOfficeAllowedPages();
        if (!allowedPages) return true;
        if (allowedPages.length === 0) {
            return route === 'dashboard';
        }
        if (allowedPages.includes(route)) return true;
        const parent = officeRouteParents[route];
        if (parent && allowedPages.includes(parent)) return true;
        return allowedPages.some(page => officeRouteParents[page] === route);
    };

    // --- UTILS ---
    const showToast = (msg, type = 'info') => {
        const container = document.getElementById('toast-container');
        const toast = document.createElement('div');
        const styles = type === 'success' ? 'bg-green-600' : type === 'error' ? 'bg-red-600' : 'bg-slate-800';
        toast.className = `${styles} text-white px-6 py-4 rounded-xl shadow-2xl text-sm flex items-center gap-4 animate-slide-in backdrop-blur-sm bg-opacity-95`;
        toast.innerHTML = `<i class="fas ${type === 'error' ? 'fa-exclamation-circle' : type === 'success' ? 'fa-check-circle' : 'fa-info-circle'} text-lg"></i> <span class="font-semibold">${msg}</span>`;
        container.appendChild(toast);
        setTimeout(() => { 
            toast.style.opacity = '0'; 
            toast.style.transform = 'translateY(-20px)';
            setTimeout(() => toast.remove(), 300); 
        }, 3000);
    };

    const logAction = (action, details) => {
        db.auditLogs.unshift({ 
            id: db.auditLogs.length + 1,
            user: currentUser.name,
            role: `${currentUser.tenantType} ${currentUser.role}`,
            action: action,
            details: details,
            timestamp: new Date().toISOString().slice(0, 16).replace('T', ' '),
            entityId: currentUser.entityId
        });
    };

    const lockSidebarNaioshColor = () => {
        document.querySelectorAll('#sidebar .naiosh-brand-accent').forEach((el) => {
            el.style.setProperty('color', '#e55050', 'important');
        });
    };

    const updateThemeVariables = (themeKey) => {
        const theme = THEMES[themeKey] || THEMES.BLUE;
        const root = document.documentElement;
        Object.entries(theme.colors).forEach(([key, value]) => {
            root.style.setProperty(`--brand-${key}`, value);
        });
        lockSidebarNaioshColor();
    };

