    const resolveHelpGuide = (route) => {
        const fallbackTitle = getTitle(route) || 'الصفحة الحالية';
        const override = helpGuideContent[route];
        const title = override?.title || `دليل ${fallbackTitle}`;
        return {
            title,
            description: override?.description || 'هذا الدليل يقدم شرحا سريعا لمحتوى الصفحة والخطوات الاساسية.',
            items: override?.items || ['راجع البيانات المعروضة بعناية.', 'استخدم الفلاتر لتضييق النتائج.', 'ابدأ بالاجراء الاهم لك.']
        };
    };

    const normalizeHelpText = (value) =>
        (value || '')
            .toString()
            .replace(/\s+/g, ' ')
            .replace(/[\u064B-\u065F]/g, '')
            .trim()
            .toLowerCase();

    const describeHelpAction = (label) => {
        const normalized = normalizeHelpText(label);
        if (!normalized) return 'تنفيذ الاجراء الموضح على الزر.';
        if (normalized.includes('اضاف') || normalized.includes('add')) return 'إضافة سجل جديد في الصفحة.';
        if (normalized.includes('تحديث') || normalized.includes('refresh')) return 'تحديث البيانات المعروضة.';
        if (normalized.includes('تنزيل') || normalized.includes('تصدير') || normalized.includes('export') || normalized.includes('csv') || normalized.includes('json') || normalized.includes('pdf')) return 'تصدير البيانات بصيغة مناسبة.';
        if (normalized.includes('طباع') || normalized.includes('print')) return 'طباعة التقرير أو القائمة الحالية.';
        if (normalized.includes('بحث') || normalized.includes('search')) return 'تنفيذ عملية البحث أو التصفية.';
        if (normalized.includes('حفظ') || normalized.includes('save')) return 'حفظ التغييرات أو السجل.';
        if (normalized.includes('اغلاق') || normalized.includes('close')) return 'إغلاق النافذة أو النموذج.';
        if (normalized.includes('اعتماد') || normalized.includes('approve')) return 'اعتماد الطلب أو السجل.';
        if (normalized.includes('ترحيل') || normalized.includes('post')) return 'ترحيل القيود أو المعاملات.';
        if (normalized.includes('تسويه') || normalized.includes('settlement')) return 'إتمام تسوية المبالغ أو الفروقات.';
        return 'تنفيذ الاجراء الموضح على الزر.';
    };

    const collectHelpButtons = () => {
        const view = document.getElementById('main-view');
        if (!view) return [];
        const buttons = Array.from(view.querySelectorAll('button'));
        const labels = [];
        buttons.forEach((button) => {
            const label = (button.textContent || '').replace(/\s+/g, ' ').trim();
            if (!label || label.length > 40) return;
            if (!labels.includes(label)) labels.push(label);
        });
        return labels.slice(0, 4).map((label) => `${label}: ${describeHelpAction(label)}`);
    };

    const collectHelpFields = () => {
        const view = document.getElementById('main-view');
        if (!view) return [];
        const labels = [];
        const labelEls = Array.from(view.querySelectorAll('label'));
        labelEls.forEach((labelEl) => {
            const label = (labelEl.textContent || '').replace(/\s+/g, ' ').trim();
            if (!label || label.length > 40) return;
            if (!labels.includes(label)) labels.push(label);
        });

        if (labels.length < 2) {
            const inputs = Array.from(view.querySelectorAll('input[placeholder], textarea[placeholder], select'));
            inputs.forEach((input) => {
                const placeholder = (input.getAttribute('placeholder') || '').replace(/\s+/g, ' ').trim();
                const label = placeholder || input.getAttribute('aria-label') || '';
                if (!label || label.length > 40) return;
                if (!labels.includes(label)) labels.push(label);
            });
        }

        return labels.slice(0, 4).map((label) => `${label}: لتحديد البيانات أو تصفية النتائج المرتبطة بالحقل.`);
    };

    const buildDynamicHelpItems = () => {
        const items = [];
        const buttonItems = collectHelpButtons();
        const fieldItems = collectHelpFields();
        if (buttonItems.length) items.push(...buttonItems);
        if (fieldItems.length) items.push(...fieldItems);
        return items;
    };

    const setHelpGuideOpen = (isOpen) => {
        const panel = document.getElementById('help-guide-panel');
        const backdrop = document.getElementById('help-guide-backdrop');
        if (!panel || !backdrop) return;
        panel.classList.toggle('is-open', isOpen);
        backdrop.classList.toggle('is-open', isOpen);
        panel.setAttribute('aria-hidden', String(!isOpen));
        backdrop.setAttribute('aria-hidden', String(!isOpen));
    };

    const updateHelpGuide = (route) => {
        const button = document.getElementById('help-guide-button');
        const titleEl = document.getElementById('help-guide-title');
        const descEl = document.getElementById('help-guide-description');
        const listEl = document.getElementById('help-guide-list');
        if (!button || !titleEl || !descEl || !listEl) return;

        const guide = resolveHelpGuide(route);
        const dynamicItems = buildDynamicHelpItems();
        const mergedItems = Array.from(new Set([...dynamicItems, ...guide.items])).slice(0, 6);
        button.setAttribute('title', guide.title);
        button.setAttribute('aria-label', guide.title);
        titleEl.textContent = guide.title;
        descEl.textContent = guide.description;
        listEl.innerHTML = mergedItems.map(item => `<li>${item}</li>`).join('');
    };

    const initHelpGuide = () => {
        const button = document.getElementById('help-guide-button');
        const closeButton = document.getElementById('help-guide-close');
        const backdrop = document.getElementById('help-guide-backdrop');
        if (!button || !closeButton || !backdrop) return;

        button.addEventListener('click', () => setHelpGuideOpen(true));
        closeButton.addEventListener('click', () => setHelpGuideOpen(false));
        backdrop.addEventListener('click', () => setHelpGuideOpen(false));
        document.addEventListener('keydown', (event) => {
            if (event.key === 'Escape') setHelpGuideOpen(false);
        });

        const currentRoute = window.currentAppRoute || 'dashboard';
        updateHelpGuide(currentRoute);
    };

