    const buildGlobalSearchIndex = () => {
        const unique = new Map();
        Object.keys(routeToPath).forEach(route => {
            const path = routeToPath[route];
            if (!path) return;
            const title = getTitle(route) || route;
            const keywords = [title, route.replace(/-/g, ' '), path].join(' ');
            const key = path;
            if (!unique.has(key)) {
                unique.set(key, { route, path, title, keywords });
            }
        });
        return Array.from(unique.values());
    };

    window.NAIOSH_SEARCH_INDEX = buildGlobalSearchIndex();

