    const submitPayment = (invId) => {
        const inv = db.invoices.find(i => i.id === invId);
        if (!inv) return showToast('الفاتورة غير موجودة', 'error');

        const paymentOption = document.querySelector('input[name="payment-option"]:checked')?.value;
        let amount = 0;
        let method = '';
        let paymentType = '';

        if (paymentOption === 'full') {
            amount = inv.amount - inv.paidAmount;
            method = document.getElementById('full-payment-method')?.value;
            paymentType = 'دفع كامل';
            if (!method) return showToast('يرجى اختيار طريقة الدفع', 'error');
        } else if (paymentOption === 'partial') {
            const selectedAmount = document.querySelector('input[name="partial-amount"]:checked')?.value;
            const customAmount = document.getElementById('custom-partial-amount')?.value;
            amount = customAmount ? parseFloat(customAmount) : parseFloat(selectedAmount);
            method = document.getElementById('partial-payment-method')?.value;
            paymentType = 'دفع جزئي';
            if (!method) return showToast('يرجى اختيار طريقة الدفع', 'error');
        } else if (paymentOption === 'installment') {
            amount = inv.amount - inv.paidAmount;
            const months = document.querySelector('input[name="installment-months"]:checked')?.value;
            const interest = document.querySelector('input[name="installment-interest"]:checked')?.value;
            method = document.getElementById('installment-payment-method')?.value;
            paymentType = `أقساط (${months} شهر - فائدة ${interest}%)`;
            if (!method) return showToast('يرجى اختيار طريقة الدفع', 'error');
        }

        if (amount <= 0 || amount > (inv.amount - inv.paidAmount)) {
            return showToast('مبلغ غير صالح', 'error');
        }

        // 1. Create Transaction
        const trxId = `TRX-${Math.floor(1000 + Math.random() * 9000)}`;
        const newTrx = {
            id: trxId,
            invoiceId: invId,
            entityId: inv.entityId,
            type: 'PAYMENT',
            amount: amount,
            method: method,
            paymentType: paymentType,
            date: new Date().toISOString().slice(0, 10),
            user: currentUser.name
        };
        db.transactions.push(newTrx);

        // 2. Update Invoice
        inv.paidAmount += amount;
        if (inv.paidAmount >= inv.amount) inv.status = 'PAID';
        else if (inv.paidAmount > 0) inv.status = 'PARTIAL_PAID';

        // 3. Add to Ledger (Immutable)
        db.ledger.unshift({
            id: db.ledger.length + 1,
            entityId: inv.entityId,
            trxId: trxId,
            date: new Date().toISOString().slice(0, 10),
            desc: `سداد (${paymentType}) للفاتورة ${invId}`,
            debit: 0,
            credit: amount,
            balance: (db.ledger[0]?.balance || 0) + amount,
            type: 'Credit'
        });

        logAction('PAYMENT', `تم تسجيل دفع ${paymentType} بمبلغ ${amount} SAR للفاتورة ${invId}`);
        document.getElementById('pay-modal').remove();
        showToast(`✅ تم تسجيل ${paymentType} بنجاح - المبلغ: ${amount.toLocaleString('en-US')} SAR`, 'success');
        loadRoute('invoices-enhanced');
    };

    const reverseTransaction = (trxId) => {
        const originalTrx = db.transactions.find(t => t.id === trxId);
        if (!originalTrx) return;
        if (confirm('هل أنت متأكد من إجراء قيد عكسي؟ سيتم خصم المبلغ من الرصيد.')) {
            // 1. Create Reversal Transaction
            const revId = `REV-${Math.floor(1000 + Math.random() * 9000)}`;
            
            // 2. Update Invoice
            const inv = db.invoices.find(i => i.id === originalTrx.invoiceId);
            if (inv) {
                inv.paidAmount -= originalTrx.amount;
                if (inv.paidAmount <= 0) inv.status = 'UNPAID';
                else if (inv.paidAmount < inv.amount) inv.status = 'PARTIAL';
            }

            // 3. Ledger Entry (Debit to reduce balance)
            db.ledger.unshift({
                id: db.ledger.length + 1,
                entityId: originalTrx.entityId,
                trxId: revId,
                date: new Date().toISOString().slice(0, 10),
                desc: `قيد عكسي (تصحيح) للمعاملة ${trxId}`,
                debit: originalTrx.amount,
                credit: 0,
                balance: (db.ledger[0]?.balance || 0) - originalTrx.amount,
                type: 'Debit'
            });

            logAction('REVERSAL', `Reversed transaction ${trxId}`);
            showToast('تم إجراء القيد العكسي بنجاح', 'success');
            loadRoute('billing');
        }
    };

    // --- DASHBOARD (Existing) --- 
    const initDashboardChart = () => {
        const ctx = document.getElementById('adsChart');
        if (!ctx) return;
        const isHq = !!ctx.closest('.hq-dashboard');
        const visibleAds = perms.getVisibleAds();
        const levels = Object.values(AD_LEVELS);
        const counts = levels.map(l => visibleAds.filter(a => a.level === l.key).length);

        if (isHq) {
            const tasks = perms.getVisibleTasks().length;
            const tickets = perms.getVisibleTickets().length;
            const users = db.entities.find(e => e.id === currentUser?.entityId)?.users || 1;
            const weekLabels = ['السبت', 'الأحد', 'الاثنين', 'الثلاثاء', 'الأربعاء', 'الخميس', 'الجمعة'];
            const base = Math.max(tasks + tickets, 3);
            const weekData = weekLabels.map((_, i) => Math.max(1, Math.round(base * (0.6 + (i % 3) * 0.15))));

            activeChart = new Chart(ctx, {
                type: 'line',
                data: {
                    labels: weekLabels,
                    datasets: [
                        {
                            label: 'النشاط التشغيلي',
                            data: weekData,
                            borderColor: '#b91c1c',
                            backgroundColor: 'rgba(185, 28, 28, 0.08)',
                            borderWidth: 3,
                            fill: true,
                            tension: 0.4,
                            pointBackgroundColor: '#fff',
                            pointBorderColor: '#b91c1c',
                            pointBorderWidth: 2,
                            pointRadius: 5,
                            pointHoverRadius: 7
                        },
                        {
                            label: 'الإعلانات',
                            data: weekLabels.map((_, i) => Math.max(0, counts[i % counts.length] || 0)),
                            borderColor: '#94a3b8',
                            backgroundColor: 'transparent',
                            borderWidth: 2,
                            borderDash: [6, 4],
                            tension: 0.35,
                            pointRadius: 3,
                            pointHoverRadius: 5
                        }
                    ]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    interaction: { mode: 'index', intersect: false },
                    plugins: {
                        legend: {
                            display: true,
                            position: 'top',
                            align: 'end',
                            labels: { font: { family: 'Cairo', size: 11 }, usePointStyle: true, boxWidth: 8 }
                        }
                    },
                    scales: {
                        y: { beginAtZero: true, grid: { color: '#f1f5f9' }, border: { display: false }, ticks: { font: { family: 'Cairo' } } },
                        x: { grid: { display: false }, border: { display: false }, ticks: { font: { family: 'Cairo', size: 11 } } }
                    }
                }
            });
            return;
        }

        activeChart = new Chart(ctx, {
            type: 'bar',
            data: {
                labels: levels.map(l => l.label.split(' ')[0]),
                datasets: [{ label: 'الإعلانات', data: counts, backgroundColor: levels.map(l => l.chartColor), borderRadius: 6 }]
            },
            options: {
                responsive: true, maintainAspectRatio: false,
                plugins: { legend: { display: false } },
                scales: {
                    y: { beginAtZero: true, grid: { color: '#f1f5f9' }, border: { display: false } },
                    x: { grid: { display: false }, border: { display: false } }
                }
            }
        });
    };

    const getHqMainMenuModules = () => ([
        { title: 'الموارد المالية', desc: 'الميزانيات، القيود، والتحليلات المالية', icon: 'fa-sack-dollar', route: 'finance', tone: 'from-emerald-500 to-teal-600' },
        { title: 'الموارد البشرية والقانونية', desc: 'الهيكل الوظيفي والالتزام والسياسات', icon: 'fa-scale-balanced', route: 'employees', tone: 'from-indigo-500 to-purple-600' },
        { title: 'الإدارة الاستراتيجية', desc: 'الأهداف والمبادرات والمخرجات التنفيذية', icon: 'fa-bullseye', route: 'executive-management', tone: 'from-amber-500 to-orange-600' },
        { title: 'إدارة العمليات', desc: 'التشغيل، الجودة، ومتابعة الأداء اليومي', icon: 'fa-gear', route: 'operations-management', tone: 'from-slate-700 to-slate-900' },
        { title: 'الجودة والسياسات', desc: 'حوكمة الجودة، السياسات التفصيلية، ومؤشرات الأداء', icon: 'fa-clipboard-check', route: 'quality-audit', tone: 'from-teal-500 to-cyan-600' },
        { title: 'الأنظمة الذكية', desc: 'التحليلات المتقدمة والأتمتة الذكية', icon: 'fa-robot', route: 'smart-systems', tone: 'from-sky-500 to-blue-600' },
        { title: 'الفروع', desc: 'إدارة فروع الدولة وربطها بالمقر', icon: 'fa-store', route: 'hierarchy', tone: 'from-rose-500 to-pink-600' },
        { title: 'الحاضنات', desc: 'برامج النمو ومتابعة الحاضنات', icon: 'fa-seedling', route: 'hierarchy', tone: 'from-green-500 to-emerald-600' },
        { title: 'المنصات', desc: 'حوكمة المنصات والخدمات الرقمية', icon: 'fa-layer-group', route: 'hierarchy', tone: 'from-violet-500 to-fuchsia-600' },
        { title: 'المكاتب', desc: 'إدارة المكاتب التابعة وربطها بالهيكل', icon: 'fa-building', route: 'hierarchy', tone: 'from-red-500 to-red-600' }
    ]);

    const getHqGreeting = () => {
        const hour = new Date().getHours();
        if (hour < 12) return 'صباح الخير';
        if (hour < 17) return 'مساء الخير';
        return 'مساء النور';
    };

    const isHqEntity = (entity, user) => (
        entity?.type === 'HQ' || user?.tenantType === 'HQ' || user?.entityId === 'HQ001' || user?.entity_id === 'HQ001'
    );

