    const renderTenantRegistration = () => {
        if (!perms.isHQ()) return renderPlaceholder('هذه الميزة متاحة فقط للمكتب الرئيسي (Super Admin)');
        return `
        <div class="max-w-4xl mx-auto animate-slide-in">
            <div class="text-center mb-8"><h2 class="text-2xl md:text-3xl font-extrabold text-slate-800">تسجيل مستأجر جديد</h2><p class="text-slate-500 mt-2">إنشاء بيئة عمل جديدة وتخصيص الموارد</p></div>
            <div class="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden p-6 md:p-8">
                <div class="grid grid-cols-1 gap-8">
                    <div><h4 class="text-lg font-bold text-slate-800 mb-4 border-b pb-2">1. بيانات المؤسسة</h4><div class="grid grid-cols-1 md:grid-cols-2 gap-4"><div><label class="block text-sm font-semibold text-slate-600 mb-2">اسم المستأجر</label><input type="text" id="reg-name" class="w-full px-4 py-3 rounded-xl border border-gray-200 outline-none"></div><div><label class="block text-sm font-semibold text-slate-600 mb-2">الموقع</label><input type="text" id="reg-location" class="w-full px-4 py-3 rounded-xl border border-gray-200 outline-none"></div></div></div>
                    <div><h4 class="text-lg font-bold text-slate-800 mb-4 border-b pb-2">2. نوع الكيان</h4><div class="grid grid-cols-2 md:grid-cols-4 gap-4">${Object.values(TENANT_TYPES).filter(t => t.id !== 'HQ').map(t => `<label class="cursor-pointer relative"><input type="radio" name="reg-type" value="${t.id}" class="peer sr-only"><div class="p-4 rounded-xl border-2 border-slate-100 peer-checked:border-brand-500 peer-checked:bg-brand-50 transition-all text-center"><i class="fas ${t.icon} text-2xl mb-2 ${t.color}"></i><div class="text-xs font-bold">${t.label}</div></div></label>`).join('')}</div></div>
                    <div><h4 class="text-lg font-bold text-slate-800 mb-4 border-b pb-2">3. خطة الاشتراك</h4><div class="grid grid-cols-1 md:grid-cols-3 gap-4">${Object.keys(SUBSCRIPTION_PLANS).map(key => `<label class="cursor-pointer relative"><input type="radio" name="reg-plan" value="${key}" class="peer sr-only"><div class="p-4 rounded-xl border-2 border-slate-100 peer-checked:border-brand-500 peer-checked:bg-brand-50 transition-all"><div class="font-bold">${SUBSCRIPTION_PLANS[key].name}</div></div></label>`).join('')}</div></div>
                    <div class="pt-4 flex justify-end gap-3"><button onclick="app.loadRoute('entities')" class="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-100">إلغاء</button><button onclick="app.submitTenantRegistration()" class="px-8 py-3 rounded-xl font-bold bg-brand-600 text-white shadow-lg">إنشاء</button></div>
                </div>
            </div>
        </div>`;
    };

    const submitTenantRegistration = () => {
        const name = document.getElementById('reg-name').value;
        const location = document.getElementById('reg-location').value;
        const type = document.querySelector('input[name="reg-type"]:checked')?.value;
        const plan = document.querySelector('input[name="reg-plan"]:checked')?.value;
        if (!name || !location || !type || !plan) return showToast('الرجاء تعبئة جميع الحقول', 'error');
        
        const newId = (type === 'BRANCH' ? 'BR' : type === 'INCUBATOR' ? 'INC' : type === 'PLATFORM' ? 'PLT' : type === 'OFFICE' ? 'OFF' : 'TNT') + Math.floor(100 + Math.random() * 900);
        
        // Save to database via API
        fetch('/api/entities', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'x-entity-type': window.currentUser?.entityType || 'HQ',
                'x-entity-id': window.currentUser?.entityId || 'HQ001'
            },
            body: JSON.stringify({
                id: newId,
                name: name,
                type: type,
                location: location,
                status: 'Active'
            })
        })
        .then(response => {
            if (!response.ok) throw new Error('فشل حفظ البيانات');
            return response.json();
        })
        .then(entity => {
            // Add to local cache
            db.entities.push(entity);
            showToast(`تم إنشاء المستأجر ${name} بنجاح!`, 'success');
            loadRoute('entities');
        })
        .catch(error => {
            console.error('Error creating entity:', error);
            showToast('حدث خطأ: ' + error.message, 'error');
        });
    };

    // Entity Management Functions
    window.manageEntity = function(entityId) {
        showToast('فتح لوحة إدارة الكيان...', 'info');
        // يمكن إضافة modal أو صفحة منفصلة لإدارة الكيان
    };

    window.suspendEntity = function(entityId) {
        if (!confirm('هل أنت متأكد من إيقاف هذا الكيان مؤقتاً؟')) return;
        
        fetch(`/api/entities/${entityId}`, {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json',
                'x-entity-type': window.currentUser?.entityType || 'HQ',
                'x-entity-id': window.currentUser?.entityId || 'HQ001'
            },
            body: JSON.stringify({ status: 'Suspended' })
        })
        .then(response => {
            if (!response.ok) throw new Error('فشل إيقاف الكيان');
            return response.json();
        })
        .then(updatedEntity => {
            // Update local cache
            const entity = db.entities.find(e => e.id === entityId);
            if (entity) entity.status = 'Suspended';
            
            logAction('SUSPEND_ENTITY', `Suspended entity ${entityId}`);
            showToast('تم إيقاف الكيان مؤقتاً', 'success');
            loadRoute('entities');
        })
        .catch(error => {
            console.error('Error suspending entity:', error);
            showToast('حدث خطأ: ' + error.message, 'error');
        });
    };

    window.reactivateEntity = function(entityId) {
        fetch(`/api/entities/${entityId}`, {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json',
                'x-entity-type': window.currentUser?.entityType || 'HQ',
                'x-entity-id': window.currentUser?.entityId || 'HQ001'
            },
            body: JSON.stringify({ status: 'Active' })
        })
        .then(response => {
            if (!response.ok) throw new Error('فشل إعادة تفعيل الكيان');
            return response.json();
        })
        .then(updatedEntity => {
            // Update local cache
            const entity = db.entities.find(e => e.id === entityId);
            if (entity) entity.status = 'Active';
            
            logAction('REACTIVATE_ENTITY', `Reactivated entity ${entityId}`);
            showToast('تم إعادة تفعيل الكيان', 'success');
            loadRoute('entities');
        })
        .catch(error => {
            console.error('Error reactivating entity:', error);
            showToast('حدث خطأ: ' + error.message, 'error');
        });
    };

    window.editEntity = function(entityId) {
        const entity = db.entities.find(e => e.id === entityId);
        if (!entity) return showToast('الكيان غير موجود', 'error');
        
        const modal = document.createElement('div');
        modal.id = 'edit-entity-modal';
        modal.className = 'fixed inset-0 bg-slate-900/60 z-[999] flex items-center justify-center backdrop-blur-sm fade-in p-4';
        modal.innerHTML = `
            <div class="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-scale-up">
                <div class="p-6 border-b border-slate-100 bg-slate-50">
                    <h3 class="font-bold text-lg text-slate-800">تعديل الكيان: ${entity.name}</h3>
                </div>
                <div class="p-6 space-y-4">
                    <div>
                        <label class="block text-sm font-bold text-slate-600 mb-2">اسم الكيان</label>
                        <input type="text" id="edit-entity-name" value="${entity.name}" class="w-full px-4 py-3 rounded-xl border border-gray-200 outline-none focus:border-brand-500">
                    </div>
                    <div>
                        <label class="block text-sm font-bold text-slate-600 mb-2">الموقع</label>
                        <input type="text" id="edit-entity-location" value="${entity.location || ''}" class="w-full px-4 py-3 rounded-xl border border-gray-200 outline-none focus:border-brand-500">
                    </div>
                </div>
                <div class="p-4 border-t border-slate-100 bg-slate-50 flex justify-end gap-3">
                    <button onclick="document.getElementById('edit-entity-modal').remove()" class="px-4 py-2 rounded-lg text-slate-500 font-bold hover:bg-slate-200">إلغاء</button>
                    <button onclick="window.saveEntityEdits('${entityId}')" class="px-6 py-2 rounded-lg bg-brand-600 text-white font-bold hover:bg-brand-700">حفظ</button>
                </div>
            </div>`;
        document.body.appendChild(modal);
    };

    window.saveEntityEdits = function(entityId) {
        const name = document.getElementById('edit-entity-name').value;
        const location = document.getElementById('edit-entity-location').value;
        
        fetch(`/api/entities/${entityId}`, {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json',
                'x-entity-type': window.currentUser?.entityType || 'HQ',
                'x-entity-id': window.currentUser?.entityId || 'HQ001'
            },
            body: JSON.stringify({ name, location })
        })
        .then(response => {
            if (!response.ok) throw new Error('فشل حفظ التعديلات');
            return response.json();
        })
        .then(updatedEntity => {
            // Update local cache
            const entity = db.entities.find(e => e.id === entityId);
            if (entity) {
                entity.name = name;
                entity.location = location;
            }
            
            logAction('EDIT_ENTITY', `Edited entity ${entityId}`);
            showToast('تم تحديث بيانات الكيان', 'success');
            document.getElementById('edit-entity-modal').remove();
            loadRoute('entities');
        })
        .catch(error => {
            console.error('Error editing entity:', error);
            showToast('حدث خطأ: ' + error.message, 'error');
        });
    };

    // Dropdown Menu Controls
    window.toggleDropdown = function(entityId) {
        const menu = document.getElementById(`dropdown-menu-${entityId}`);
        const allMenus = document.querySelectorAll('[id^="dropdown-menu-"]');
        
        // Close all other dropdowns
        allMenus.forEach(m => {
            if (m.id !== `dropdown-menu-${entityId}`) {
                m.classList.add('hidden');
            }
        });
        
        // Toggle current dropdown
        menu.classList.toggle('hidden');
    };

    window.closeAllDropdowns = function() {
        const allMenus = document.querySelectorAll('[id^="dropdown-menu-"]');
        allMenus.forEach(m => m.classList.add('hidden'));
    };

    // Close dropdowns when clicking outside
    document.addEventListener('click', function(event) {
        const isDropdownButton = event.target.closest('[onclick*="toggleDropdown"]');
        const isDropdownMenu = event.target.closest('[id^="dropdown-menu-"]');
        
        if (!isDropdownButton && !isDropdownMenu) {
            window.closeAllDropdowns();
        }
    });

    window.moveEntityUp = function(entityId) {
        const index = db.entities.findIndex(e => e.id === entityId);
        if (index > 0) {
            [db.entities[index - 1], db.entities[index]] = [db.entities[index], db.entities[index - 1]];
            logAction('MOVE_ENTITY_UP', `Moved entity ${entityId} up`);
            showToast('تم نقل الكيان للأعلى', 'success');
            loadRoute('entities');
        } else {
            showToast('الكيان بالفعل في الموضع الأول', 'info');
        }
    };

    window.deleteEntityPermanent = function(entityId) {
        if (!confirm('⚠️ تحذير: هل أنت متأكد من الحذف النهائي؟\n\nهذا الإجراء لا يمكن التراجع عنه وسيتم حذف جميع البيانات المرتبطة.')) return;
        
        fetch(`/api/entities/${entityId}`, {
            method: 'DELETE',
            headers: {
                'Content-Type': 'application/json',
                'x-entity-type': window.currentUser?.entityType || 'HQ',
                'x-entity-id': window.currentUser?.entityId || 'HQ001'
            }
        })
        .then(response => {
            if (!response.ok) throw new Error('فشل حذف الكيان');
            return response.json();
        })
        .then(data => {
            // Remove from local cache
            const index = db.entities.findIndex(e => e.id === entityId);
            if (index !== -1) {
                const entityName = db.entities[index].name;
                db.entities.splice(index, 1);
                logAction('DELETE_ENTITY_PERMANENT', `Permanently deleted entity ${entityId}`);
                showToast(`تم حذف ${entityName} نهائياً`, 'success');
            }
            loadRoute('entities');
        })
        .catch(error => {
            console.error('Error deleting entity:', error);
            showToast('حدث خطأ: ' + error.message, 'error');
        });
    };

