    const getRecordsSecurityLogStats = (rows) => {
        return rows.reduce((acc, row) => {
            acc.total += 1;
            if (row.status === 'ناجح') acc.success += 1;
            if (row.status === 'تنبيه') acc.alerts += 1;
            if (row.status === 'قيد الانتظار') acc.pending += 1;
            return acc;
        }, { total: 0, success: 0, alerts: 0, pending: 0 });
    };

